// ... dentro de FormularioOferta ...
const [preview, setPreview] = useState(null);

const handleImageChange = (e) => {
  const file = e.target.files[0];
  if (file) {
    // Esto crea una URL temporal para mostrar la imagen sin subirla a ningún lado aún
    const reader = new FileReader();
    reader.onloadend = () => {
      setPreview(reader.result);
      setFormData({ ...formData, imagen: reader.result });
    };
    reader.readAsDataURL(file);
  }
};

// En el JSX, antes del botón "Publicar Ahora":
<div style={inputGroup}>
  <label style={labelStyle}><ImageIcon size={16} /> Foto del Producto</label>
  <div style={imageContainerStyle}>
    {preview ? (
      <img src={preview} alt="Vista previa" style={previewImageStyle} />
    ) : (
      <div style={placeholderStyle}>
        <input 
          type="file" 
          accept="image/*" 
          onChange={handleImageChange} 
          style={fileInputStyle} 
        />
        <span>Click para subir foto</span>
      </div>
    )}
  </div>
</div>
